import fs from "node:fs";
import path from "node:path";
import { fileURLToPath } from "node:url";

const root = path.join(path.dirname(fileURLToPath(import.meta.url)), "..");
let origin = (process.env.MEETLY_API_ORIGIN || "").trim().replace(/\/$/, "");
if (origin && !/^https?:\/\//i.test(origin)) origin = "https://" + origin;
const content =
  "// Auto-generated by scripts/write-meetly-env.mjs (npm run build:client)\n" +
  "// Set MEETLY_API_ORIGIN when the UI is on another host (e.g. Vercel) and the API on Cloudflare.\n" +
  `window.__MEETLY_API_ORIGIN__=${JSON.stringify(origin)};\n`;

fs.writeFileSync(path.join(root, "public", "meetly-env.js"), content);
